INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline','uti_management','{"پیشاب کی نالی","جلن","UTI","پیشاب"}','پیشاب کی نالی کا انفیکشن','## UTI\n\n**غیر پیچیدہ:** نائٹروفیورانٹوئن 100mg×2 (5 دن)\n**متبادل:** سیپروفلوکساسین 500mg×2 (3 دن)\n**حمل:** اموکسیسیلین یا سیفالیکسین\n\n**⚠️ بخار >38.5 + کمر درد = گردے کا انفیکشن','ur','NICE',6,true),
('clinical_guideline','peptic_ulcer','{"السر","تیزابیت","H.pylori","معدہ"}','معدے کا السر','## معدے کا السر\n\n**H.pylori علاج (14 دن):**\n- اومیپرازول 20mg×2\n- اموکسیسیلین 1g×2\n- کلیریتھرومائسین 500mg×2\n\n**⚠️ خون کی قے، وزن میں کمی → فوری حوالہ','ur','ACG',6,true),
('clinical_guideline','epilepsy','{"مرگی","دورے","تشنج","مرگی دوائیں"}','مرگی کا علاج','## مرگی\n\n**پہلی لائن:**\n- عمومی دورے: ویلپرویٹ 500-2000mg\n- جزوی دورے: کاربامازپین 400-1200mg\n- حاملہ: لیموٹریجین\n\n**⚠️ دوا اچانک بند نہ کریں','ur','ILAE',6,true),
('clinical_guideline','gout','{"نقرس","یورک ایسڈ","جوڑ درد","گاؤٹ"}','نقرس کا علاج','## نقرس\n\n**شدید حملہ:** کولچیسین 0.5mg×3 یا انڈومیتھاسین 50mg×3\n**وقایہ:** ایلوپیورینول 100-300mg\n**ہدف:** یورک ایسڈ <6 mg/dL\n\n**⚠️ حملے کے دوران ایلوپیورینول شروع نہ کریں','ur','ACR',6,true),
('clinical_guideline','heart_failure','{"دل کی ناکامی","سانس تنگی","ورم","پاؤں سوجن"}','دل کی ناکامی','## دل کی ناکامی\n\n**علاج:**\n- ACE inhibitor: اینالاپریل 2.5-20mg\n- بیٹا بلاکر: بیسوپرولول 1.25-10mg\n- ڈائیوریٹک: فیوروسیمائیڈ 20-80mg\n\n**⚠️ شدید سانس تنگی، پھیپھڑوں میں پانی → ایمرجنسی','ur','ESC',6,true),
('clinical_guideline','pneumonia','{"نمونیا","پھیپھڑوں کا انفیکشن","بخار","کھانسی"}','نمونیا کا علاج','## نمونیا\n\n**ہلکا:** اموکسیسیلین 500mg×3 (5 دن)\n**درمیانہ:** اموکسیسیلین-کلاویولانیٹ + ایزیتھرومائسین\n\n**CURB-65 ≥3:** ہسپتال داخلہ\n**⚠️ SpO2 <92% → فوری آکسیجن','ur','BTS',6,true),
('clinical_guideline','migraine','{"درد سر","آدھا سر","مائیگرین","متلی"}','مائیگرین کا علاج','## مائیگرین\n\n**علاج:** سوماٹرپٹان 50-100mg + آئبوپروفین 400mg\n**وقایہ (≥4 حملے/ماہ):** پروپرانولول 40-160mg\n\n**⚠️ بدترین سر درد، نئی عصبی علامات → فوری حوالہ','ur','NICE',6,true),
('clinical_guideline','osteoporosis','{"ہڈی کمزوری","آسٹیوپوروسس","کیلشیم","DEXA"}','ہڈیوں کی کمزوری','## ہڈیوں کی کمزوری\n\n**تشخیص:** DEXA T-score ≤ -2.5\n**علاج:**\n- کیلشیم 1000mg + وٹامن D 800IU روزانہ\n- ایلینڈرونیٹ 70mg ہفتہ وار\n\n**⚠️ صبح خالی پیٹ کھڑے ہو کر لیں','ur','NOF',6,true),
('clinical_guideline','iron_deficiency','{"آئرن کمی","خون کی کمی","فیریٹین","لوہا"}','آئرن کی کمی','## آئرن کی کمی\n\n**تشخیص:** فیریٹین <30، MCV <80\n**علاج:** فیرس سلفیٹ 200mg×2-3 + وٹامن C\n**IV آئرن:** اگر فموی برداشت نہ ہو یا Hb <8\n\n**متابعہ:** CBC 4-8 ہفتے بعد','ur','WHO',6,true),
('clinical_guideline','wound_care','{"زخم","ٹانکے","صفائی","ڈریسنگ"}','زخموں کی دیکھ بھال','## زخموں کی دیکھ بھال\n\n**صفائی:** نمکین محلول سے دھوئیں\n**ٹانکے:** صاف زخم <6 گھنٹے\n**ٹیٹنس:** آلودہ زخم >5 سال سے ویکسین\n\n**⚠️ چہرے، نسوں، جوڑوں کے زخم → سرجن','ur','WHO',6,true),
('clinical_guideline','burns','{"جلنا","آگ","پانی گرم","جلد"}','جلنے کا علاج','## جلنا\n\n**ابتدائی:** 20 منٹ بہتے پانی سے ٹھنڈا کریں\n**⚠️ برف، ٹوتھ پیسٹ نہ لگائیں\n**سیال:** 4mL × وزن × فیصد جلنا\n\n**حوالہ:** >10% جسم، چہرے/ہاتھ، بجلی/کیمیائی','ur','WHO',6,true),
('clinical_guideline','fracture_first_aid','{"ہڈی ٹوٹنا","کسر","سپلنٹ","ابتدائی طبی"}','ہڈی ٹوٹنے کی ابتدائی مدد','## ہڈی ٹوٹنا\n\n**ابتدائی مدد:**\n- متاثرہ حصے کو حرکت نہ دیں\n- سپلنٹ لگائیں\n- برف کی ٹکور\n\n**⚠️ فوری حوالہ:** کھلا فریکچر، خون بہنا، نبض غائب','ur','WHO',6,true),
('clinical_guideline','malaria','{"ملیریا","بخار","مچھر","پلازموڈیم"}','ملیریا کا علاج','## ملیریا\n\n**P. falciparum:** ACT 3 دن\n**P. vivax:** کلوروکوین + پرائماکوین 14 دن\n**شدید:** آرٹیسونیٹ IV\n\n**🚨 بے ہوشی، شدید خون کی کمی، گردے فیل → ایمرجنسی','ur','WHO',6,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide','urinary_symptoms','{"پیشاب علامات","جلن","بار بار پیشاب","خون"}','پیشاب کی علامات','## پیشاب کی علامات\n\n**جلن + بار بار:** UTI\n**خون:** پتھری، انفیکشن، ٹیومر\n**رکاوٹ:** پروسٹیٹ بڑھنا\n\n**⚠️ بغیر درد خون = ٹیومر سے بچاؤ کا معائنہ','ur','Custom',5,true),
('symptom_guide','skin_rash','{"جلد پر دانے","خارش","ایگزیما","فنگس"}','جلد کے دانے','## جلد کے دانے\n\n**خارش + خشکی:** ایگزیما\n**گول + واضح کنارے:** فنگل\n**ایک لائن میں چھالے:** ہرپس زوسٹر\n**چہرے پر تتلی:** لوپس\n\n**⚠️ دانے + بخار + جوڑ درد → فوری معائنہ','ur','Custom',5,true),
('symptom_guide','eye_redness','{"آنکھ سرخ","آشوب چشم","نظر دھندلی","آنکھ درد"}','آنکھ کی سرخی','## آنکھ سرخ\n\n**خارج:** آشوب چشم\n**روشنی سے تکلیف + درد:** آئریٹس\n**شدید درد + دھندلی نظر:** گلوکوما\n\n**⚠️ درد + نظر کم = فوری آنکھوں کا ڈاکٹر','ur','Custom',5,true),
('symptom_guide','ear_pain','{"کان درد","کان بہنا","سماعت کم","ٹنائٹس"}','کان کا درد','## کان درد\n\n**بچے + بخار:** درمیانی کان (اموکسیسیلین)\n**تیراکی کے بعد:** بیرونی کان (قطرے)\n**چکر + آواز:** مینیئر\n\n**⚠️ اچانک سماعت ختم = فوری حوالہ','ur','Custom',5,true),
('symptom_guide','back_pain','{"کمر درد","ڈسک","عرق النساء","ریڑھ"}','کمر کا درد','## کمر درد\n\n**عام (90%):** مسکن + ورزش\n**ٹانگ تک درد:** عرق النساء\n**⚠️ خطرناک علامات:**\n- ٹانگوں میں کمزوری\n- پیشاب/پاخانہ قابو نہ رہے\n→ **فوری حوالہ**','ur','NICE',5,true),
('symptom_guide','weight_loss','{"وزن کم","کمزوری","بھوک","میٹابولزم"}','غیر ارادی وزن میں کمی','## وزن کمی (>5% چھ ماہ میں)\n\n**وجوہات:** تھائرائیڈ، شوگر، ٹی بی، کینسر، ڈپریشن\n**ٹیسٹ:** CBC، TSH، شوگر، ESR، سینے کا ایکسرے\n\n**⚠️ >10% کمی + عمومی علامات → فوری حوالہ','ur','Custom',5,true),
('symptom_guide','fatigue','{"تھکاوٹ","کمزوری","توانائی نہیں","سستی"}','مسلسل تھکاوٹ','## تھکاوٹ\n\n**عام وجوہات:**\n- خون کی کمی\n- تھائرائیڈ\n- شوگر\n- ڈپریشن\n- وٹامن D/B12 کمی\n\n**ٹیسٹ:** CBC، آئرن، TSH، شوگر، B12، وٹامن D\n\n**⚠️ تھکاوٹ + وزن کمی + رات کو پسینہ → فوری','ur','Custom',5,true),
('symptom_guide','edema','{"سوجن","ورم","پاؤں سوجن","پانی جمنا"}','سوجن اور ورم','## سوجن\n\n**ایک ٹانگ:** DVT، انفیکشن\n**دونوں ٹانگیں:** دل، گردے، جگر\n**صبح چہرے پر:** گردے\n**حمل + سوجن + BP:** تسمم حمل\n\n**⚠️ اچانک ایک ٹانگ سوجن + درد = DVT → فوری','ur','Custom',5,true),
('symptom_guide','fever','{"بخار","تپ","انفیکشن","حرارت"}','بخار کا جائزہ','## بخار\n\n**حاد (<7 دن):** نزلہ، UTI، ملیریا\n**نیم حاد (7-21):** ٹائیفائیڈ، خراج\n**دائمی (>21):** ٹی بی، HIV، کینسر\n\n**⚠️ بخار + دانے + گردن اکڑنا = گردن توڑ بخار → فوری','ur','Custom',5,true),
('symptom_guide','sore_throat','{"گلا درد","ٹانسل","نگلنے میں تکلیف","گلا"}','گلے کا درد','## گلے کا درد\n\n**وائرل (70%):** مسکن + گرم مشروبات\n**بیکٹیریل:** اموکسیسیلین 500mg×3 (10 دن)\n**Centor:** بخار، پیپ، کھانسی نہیں، غدود سوجے\n\n**⚠️ نگلنے/سانس میں دشواری → فوری حوالہ','ur','NICE',5,true),
('symptom_guide','constipation','{"قبض","پاخانہ سخت","ریشہ","جلاب"}','قبض','## قبض\n\n**علاج:**\n1. ریشہ دار غذا + پانی + حرکت\n2. لیکٹولوز 15-30mL\n3. بیساکوڈل یا سینا\n\n**⚠️ >50 سال + نئی تبدیلی، خون، وزن کمی → کولونوسکوپی','ur','NICE',5,true),
('symptom_guide','nausea_vomiting','{"متلی","قے","الٹی","معدہ خراب"}','متلی اور قے','## متلی/قے\n\n**وجوہات:** معدہ، حمل، ادویات، مائیگرین\n**علاج:** میٹوکلوپرامائیڈ 10mg یا اونڈانسیٹرون 4mg\n\n**⚠️ خون کی قے، شدید جفاف → ایمرجنسی','ur','Custom',5,true),
('symptom_guide','anxiety','{"گھبراہٹ","بے چینی","خوف","دل دھڑکنا"}','گھبراہٹ اور بے چینی','## گھبراہٹ\n\n**GAD-7:** >10 = معتدل-شدید\n**علامات:** دھڑکن، پسینہ، کانپنا، سانس تنگی\n**علاج:** CBT + سرٹرالین 50mg\n\n**🚨 پینک اٹیک:** تسلی + آہستہ سانس','ur','NICE',5,true),
('symptom_guide','dyspnea','{"سانس تنگی","سانس پھولنا","آکسیجن","پھیپھڑے"}','سانس کی تنگی','## سانس تنگی\n\n**فوری:** دمہ (بخاخ)، PE (سینہ درد + تیز دھڑکن)\n**دائمی:** COPD، دل ناکامی، خون کمی\n\n**⚠️ SpO2 <92%، نیلاہٹ، بول نہ سکے → فوری ایمرجنسی','ur','BTS',5,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide','insomnia','{"insomnia","sleep","difficulty sleeping","restless"}','Insomnia Evaluation','## Insomnia\n\n**Assessment:**\n- Duration: acute (<3mo) vs chronic\n- Sleep hygiene evaluation\n- Screen for depression, anxiety, pain\n\n**Non-pharmacological (first-line):**\n- CBT-I (cognitive behavioral therapy)\n- Sleep hygiene: fixed schedule, dark room, no screens\n\n**Pharmacological:**\n- Short-term: melatonin 2-5mg\n- Avoid benzodiazepines long-term\n\n**⚠️ Refer if:** daytime sleepiness, snoring (OSA screen)','en','NICE',5,true),
('symptom_guide','tremor','{"tremor","shaking","Parkinson","essential tremor"}','Tremor Evaluation','## Tremor\n\n**Resting tremor:** Parkinsonism (pill-rolling)\n**Action/postural:** Essential tremor (bilateral, improved with alcohol)\n**Intention:** Cerebellar disease\n\n**Workup:** TSH, LFTs, medication review\n**Treatment:** Propranolol (essential), Levodopa (Parkinson)\n\n**⚠️ Refer if:** unilateral, progressive, with rigidity/bradykinesia','en','Custom',5,true),
('drug_reference','gabapentin','{"غابابنتین","اعصابی درد","مرگی","نیوروپیتھی"}','غابابنتین','## غابابنتین\n\n**استعمال:** اعصابی درد، مرگی\n**خوراک:** 300mg سے شروع، بتدریج بڑھائیں 900-3600mg/دن\n**ضمنی اثرات:** غنودگی، چکر، وزن بڑھنا\n\n**⚠️ اچانک بند نہ کریں','ur','BNF',7,true),
('drug_reference','gabapentin_ar','{"غابابنتين","ألم أعصاب","صرع","نيوروباثي"}','غابابنتين','## غابابنتين\n\n**الاستخدام:** ألم الأعصاب، صرع\n**الجرعة:** 300mg بداية، تزداد تدريجياً حتى 900-3600mg/يوم\n**الآثار:** نعاس، دوخة، زيادة وزن\n\n**⚠️ لا تتوقف فجأة','ar','BNF',7,true),
('symptom_guide','insomnia_ar','{"أرق","نوم","صعوبة النوم","سهر"}','الأرق','## الأرق\n\n**التقييم:** حاد (<3 أشهر) أم مزمن\n**العلاج غير الدوائي (أولاً):**\n- نظافة النوم: جدول ثابت، غرفة مظلمة\n- العلاج السلوكي المعرفي\n\n**الدوائي:** ميلاتونين 2-5mg قصير المدى\n\n**⚠️ إحالة:** نعاس نهاري، شخير (انقطاع النفس)','ar','NICE',5,true),
('symptom_guide','insomnia_ur','{"نیند نہ آنا","بے خوابی","نیند","بے آرامی"}','بے خوابی','## بے خوابی\n\n**جائزہ:** حاد (<3 ماہ) یا دائمی\n**غیر دوائی علاج (پہلے):**\n- نیند کی عادات: مقررہ وقت، اندھیرا کمرہ\n- CBT\n\n**دوائی:** میلاٹونین 2-5mg مختصر مدت\n\n**⚠️ دن میں نیند، خراٹے → نیند کا ٹیسٹ','ur','NICE',5,true);